const meta = { type: "misc", docs: { description: "demo plugin rule" }, schema: null }

class PluginRule {
  constructor(reporter) {
    this.reporter = reporter
    this.ruleId = "plugin-rule-test" // loader lo convertirá a demo/plugin-rule-test
    this.meta = meta
  }

  SourceUnit(node) {
    this.reporter.errorAt(1, 0, this.ruleId, "plugin rule executed")
  }
}

module.exports = PluginRule